import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly sanitize user input by escaping special characters
        String sanitizedInput = "";
        try {
            sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Error while encoding user input");
        }

        // Print the sanitized output
        System.out.println("Welcome, " + sanitizedInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
